import { NextRequest, NextResponse } from "next/server";
import OpenAI from "openai";

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

const SYSTEM_PROMPT = `You are StudyAI, an expert AI tutor and student assistant. 
Your role is to help students learn effectively by explaining concepts clearly, answering academic questions, 
helping with homework, summarizing content, and providing study tips.

Guidelines:
- Always use clear, educational language appropriate for students
- Break down complex topics into digestible parts
- Use examples, analogies, and step-by-step explanations when helpful
- Format answers with headings, bullet points, and numbered lists when it improves clarity
- Encourage critical thinking rather than just giving answers
- Be encouraging, patient, and supportive
- When explaining math or science, show steps clearly
- Keep responses thorough but concise`;

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { question, history = [] } = body;

    if (!question || typeof question !== "string" || question.trim() === "") {
      return NextResponse.json({ error: "Question is required" }, { status: 400 });
    }

    if (!process.env.OPENAI_API_KEY) {
      return NextResponse.json({ error: "OpenAI API key not configured" }, { status: 500 });
    }

    const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
      { role: "system", content: SYSTEM_PROMPT },
      ...history.slice(-20).map((m: { role: string; content: string }) => ({
        role: m.role as "user" | "assistant",
        content: m.content,
      })),
      { role: "user", content: question.trim() },
    ];

    const completion = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages,
      temperature: 0.7,
      max_tokens: 1500,
    });

    const answer = completion.choices[0]?.message?.content ?? "I couldn't generate a response. Please try again.";
    return NextResponse.json({ answer });
  } catch (error: unknown) {
    console.error("[/api/ask] Error:", error);
    const message = error instanceof Error ? error.message : "Internal server error";
    return NextResponse.json({ error: message }, { status: 500 });
  }
}
